import { BOX_SIZE, SUDOKU_SIZE } from '@sudoku/constants';
import { decodeSencode, encodeSudoku } from '@sudoku/sencode';
import { generateSudoku, solveSudoku } from '@sudoku/sudoku';
import { derived, writable } from 'svelte/store';
import { hints } from './hints';
import { createSudoku, createGame } from '../../../domain/index.js';

let currentGame = null;

const _grid = writable(emptyGrid());       // original puzzle
const _userGrid = writable(emptyGrid());   // current board via domain
const _canUndo = writable(false);
const _canRedo = writable(false);

function emptyGrid() {
	return Array.from({ length: SUDOKU_SIZE }, () => Array(SUDOKU_SIZE).fill(0));
}

/**
 */
function syncFromDomain() {
	_userGrid.set(currentGame.getSudoku().getGrid());
	_canUndo.set(currentGame.canUndo());
	_canRedo.set(currentGame.canRedo());
}

/**
 */
function initGame(puzzleGrid) {
	const sudoku = createSudoku(puzzleGrid);
	currentGame = createGame({ sudoku });
	_grid.set(puzzleGrid.map(row => [...row]));
	syncFromDomain();
}

export const grid = {
	subscribe: _grid.subscribe,

	generate(difficulty) {
		initGame(generateSudoku(difficulty));
	},

	decodeSencode(sencode) {
		initGame(decodeSencode(sencode));
	},

	get(gridStore, x, y) {
		return gridStore[y][x];
	},

	getSencode(gridStore) {
		return encodeSudoku(gridStore);
	},
};

export const userGrid = {
	subscribe: _userGrid.subscribe,

	set: (pos, value) => {
		if (currentGame) {
		
			const currentGrid = currentGame.getSudoku().getGrid();
			if (currentGrid[pos.y][pos.x] !== value) {
				currentGame.guess({ row: pos.y, col: pos.x, value });
				syncFromDomain();
			}
		}
	},

	applyHint: (pos) => {
		if (currentGame) {
			hints.useHint();
			const currentGrid = currentGame.getSudoku().getGrid();
			const solvedSudoku = solveSudoku(currentGrid);
			const hintValue = solvedSudoku[pos.y][pos.x];
			if (currentGrid[pos.y][pos.x] !== hintValue) {
				currentGame.guess({ row: pos.y, col: pos.x, value: hintValue });
				syncFromDomain();
			}
		}
	},
};

export const canUndo = { subscribe: _canUndo.subscribe };
export const canRedo = { subscribe: _canRedo.subscribe };

export function undo() {
	if (currentGame) {
		currentGame.undo();
		syncFromDomain();
	}
}

export function redo() {
	if (currentGame) {
		currentGame.redo();
		syncFromDomain();
	}
}

export const invalidCells = derived(_userGrid, $userGrid => {
	const _invalidCells = [];

	const addInvalid = (x, y) => {
		const xy = x + ',' + y;
		if (!_invalidCells.includes(xy)) _invalidCells.push(xy);
	};

	for (let y = 0; y < SUDOKU_SIZE; y++) {
		for (let x = 0; x < SUDOKU_SIZE; x++) {

			const value = $userGrid[y][x];

			if (value) {
				for (let i = 0; i < SUDOKU_SIZE; i++) {
					// Check the row
					if (i !== x && $userGrid[y][i] === value) {
						addInvalid(x, y);
					}

					// Check the column
					if (i !== y && $userGrid[i][x] === value) {
						addInvalid(x, i);
					}
				}

				// Check the box
				const startY = Math.floor(y / BOX_SIZE) * BOX_SIZE;
				const endY = startY + BOX_SIZE;
				const startX = Math.floor(x / BOX_SIZE) * BOX_SIZE;
				const endX = startX + BOX_SIZE;
				for (let row = startY; row < endY; row++) {
					for (let col = startX; col < endX; col++) {
						if (row !== y && col !== x && $userGrid[row][col] === value) {
							addInvalid(col, row);
						}
					}
				}
			}

		}
	}

	return _invalidCells;
}, []);